module RefModule(
    input [1:0] in,
    output out0, out1, out2, out3
    );reg [3:0] input_data;

assign out0 = input_data[0];
assign out1 = input_data[1];
assign out2 = input_data[2];
assign out3 = input_data[3];

always @ (*)
    case (in)
    2'b00: input_data = 4'b0001;
    2'b01: input_data = 4'b0010;
    2'b10: input_data = 4'b0100;
    2'b11: input_data = 4'b1000;
    endcase

endmodule
